import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Rule Authoring","description":"","frontmatter":{},"headers":[],"relativePath":"settings/rule-authoring.md","filePath":"settings/rule-authoring.md","lastUpdated":1782687333000}'),o={name:"settings/rule-authoring.md"};function r(l,e,n,d,h,c){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="rule-authoring" tabindex="-1">Rule Authoring <a class="header-anchor" href="#rule-authoring" aria-label="Permalink to &quot;Rule Authoring&quot;">​</a></h1><p>EasyApi understands standard HTTP frameworks (Spring MVC, WebFlux, JAX-RS, Feign) out of the box — <strong>most projects need no custom rules</strong>. For custom framework behaviour the scanner can&#39;t see (e.g. a <code>jakarta.servlet.Filter</code> that requires a header, or a <code>ResponseBodyAdvice</code> that wraps every response in an envelope), use the built-in AI Assistant or the external skill to detect it and generate the rule. See <a href="./config-rule">Available Config Rules</a> for the full rule key catalog.</p><p>EasyYapi 3.x offers <strong>two ways</strong> to author rules. Both write to the same place — <code>.easyapi/*.rules</code> files at project (<code>&lt;project&gt;/.easyapi/</code>) or global (<code>~/.easyapi/</code>) scope. See <a href="./local-file-config">Local Config File</a> for the folder model.</p><table tabindex="0"><thead><tr><th>Way</th><th>Best for</th></tr></thead><tbody><tr><td><a href="#built-in-ai-assistant">Built-in AI Assistant</a></td><td>Quick one-offs inside the IDE; scanning the current project for hidden framework behaviour</td></tr><tr><td><a href="#external-easy-yapi-assistant-skill">External <code>easy-yapi-assistant</code> skill</a></td><td>Driving rule authoring from an external AI tool (CLI / IDE agent / CI); requires installing the skill</td></tr></tbody></table><hr><h2 id="built-in-ai-assistant" tabindex="-1">Built-in AI Assistant <a class="header-anchor" href="#built-in-ai-assistant" aria-label="Permalink to &quot;Built-in AI Assistant&quot;">​</a></h2><p>EasyYapi 3.0 ships a provider-neutral AI assistant (LangChain4j-backed) embedded in the Rules tab. It reads your existing rules, reasons about your request in natural language, proposes rule content, and saves it to a <code>.easyapi/*.rules</code> file you choose. The assistant <strong>never writes files without your explicit approval</strong> — every state-changing action requires an Approve click.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ol><li>Open <strong>Settings → EasyApi → AI</strong> (a dedicated top-level tab).</li><li>Choose a provider: <code>OPENAI</code>, <code>ANTHROPIC</code>, <code>GEMINI</code>, <code>OLLAMA</code>, <code>AZURE_OPENAI</code>, or <code>CUSTOM</code>.</li><li>Enter the API key (stored securely in IntelliJ&#39;s <code>PasswordSafe</code>), the base URL (auto-filled for known providers), and the model name.</li><li>Click <strong>Test Connection</strong> to verify. The test uses the on-screen field values, so you can verify before clicking Apply/OK.</li><li>(Optional) Click <strong>Auto-detect</strong> to let EasyYapi infer the provider from environment variables (<code>OPENAI_API_KEY</code>, <code>ANTHROPIC_API_KEY</code>, <code>OLLAMA_HOST</code>, …).</li></ol><h3 id="authoring-a-rule" tabindex="-1">Authoring a rule <a class="header-anchor" href="#authoring-a-rule" aria-label="Permalink to &quot;Authoring a rule&quot;">​</a></h3><ol><li>Open <strong>Settings → EasyApi → Rules</strong>.</li><li>Click <strong>Chat</strong> (bottom action bar) to reveal the inline AI panel.</li><li>Describe what you want in natural language. Examples: <ul><li>&quot;Rename all endpoints in <code>UserController</code> to start with <code>fetch_</code>.&quot;</li><li>&quot;Add the tag <code>internal</code> to all classes in the <code>internal</code> package.&quot;</li><li>&quot;Ignore all fields named <code>internalCache</code> in <code>UserDto</code>.&quot;</li></ul></li><li>The assistant reads your existing rules, reasons about the request, and proposes rule content.</li><li>Review the proposal card. You can <strong>Edit</strong> the content before saving.</li><li>Click <strong>Save…</strong> — choose Global (<code>~/.easyapi/</code>) or Project (<code>&lt;project&gt;/.easyapi/</code>) scope + filename.</li><li>The rule file is written into the chosen folder and the config is reloaded immediately (the folder is the source of truth — no settings-list registration needed).</li></ol><h3 id="detecting-hidden-framework-behaviour-magic" tabindex="-1">Detecting hidden framework behaviour (Magic) <a class="header-anchor" href="#detecting-hidden-framework-behaviour-magic" aria-label="Permalink to &quot;Detecting hidden framework behaviour (Magic)&quot;">​</a></h3><p>Click <strong>Magic</strong> (bottom action bar) instead of <strong>Chat</strong> to run a built-in review-and-detect instruction. Magic will:</p><ol><li>Review your existing rules for gaps.</li><li>Scan the project for custom framework patterns the scanner can&#39;t see — Filters / Interceptors that require a header, <code>ResponseBodyAdvice</code> wrappers, <code>HandlerMethodArgumentResolver</code> injections, meta-annotations, custom security annotations.</li><li>Propose a rule for each detection.</li></ol><p>Each proposal still goes through the same Approve → Save flow as Chat. You stay in control of what gets written.</p><h3 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h3><ul><li>The assistant has access to the plugin&#39;s knowledge base, so it knows the full rule key catalog.</li><li>Ask it to &quot;list my current rules&quot; before proposing changes — useful for understanding the starting state.</li><li>The assistant addresses rule files by <strong>name</strong> (e.g. <code>security.rules</code>), not absolute path. It resolves the name against the tracked <code>.easyapi/</code> folders.</li></ul><hr><h2 id="external-easy-yapi-assistant-skill" tabindex="-1">External <code>easy-yapi-assistant</code> skill <a class="header-anchor" href="#external-easy-yapi-assistant-skill" aria-label="Permalink to &quot;External `easy-yapi-assistant` skill&quot;">​</a></h2><p>For teams that drive rule authoring from an external AI tool — a terminal-based agent, an IDE assistant, or a CI helper — install the <code>easy-yapi-assistant</code> skill. The skill uses the <strong>same knowledge base</strong> as the in-IDE assistant, so external tools and the built-in assistant always author rules from the same source of truth.</p><h3 id="what-the-skill-exposes" tabindex="-1">What the skill exposes <a class="header-anchor" href="#what-the-skill-exposes" aria-label="Permalink to &quot;What the skill exposes&quot;">​</a></h3><ul><li><strong>Rule-key catalog</strong> — the canonical list of supported rule keys and their aggregation modes.</li><li><strong>Custom-Pattern Catalog</strong> — the same patterns the Magic button detects (Filter / Interceptor / ResponseBodyAdvice / HandlerMethodArgumentResolver / meta-annotations), with detection signals and rule recipes for each.</li><li><strong>Helper scripts</strong> — for inspecting existing rules in <code>.easyapi/</code> folders without opening the IDE (listing rule files, reading a named file, finding rules for a given key).</li></ul><h3 id="when-to-use-the-skill" tabindex="-1">When to use the skill <a class="header-anchor" href="#when-to-use-the-skill" aria-label="Permalink to &quot;When to use the skill&quot;">​</a></h3><ul><li>Author rules from a terminal AI tool that has file access but not IntelliJ&#39;s PSI.</li><li>Batch-detect custom framework behaviour across multiple repos in CI.</li><li>Generate rule stubs that a human reviewer finalises inside the IDE.</li><li>Keep rule authoring consistent when some team members use the IDE assistant and others use an external tool.</li></ul><h3 id="how-to-use-it" tabindex="-1">How to use it <a class="header-anchor" href="#how-to-use-it" aria-label="Permalink to &quot;How to use it&quot;">​</a></h3><ol><li><p>Install the skill globally:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tangcent/easy-yapi</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>This installs the <code>easy-yapi-assistant</code> skill. Once installed, your AI coding assistant (Trae, Cursor, Cline, Continue, etc.) will automatically invoke it when you ask to add or modify EasyApi rules.</p></li><li><p>In your AI coding assistant, ask for the rule you want — e.g. &quot;Add a rule that ignores all fields annotated with <code>@Internal</code>.&quot; The assistant uses the skill&#39;s bundled knowledge base (a synced copy of the rule guide) to author the rule.</p></li><li><p>(Optional) The skill can inspect the current state of your <code>.easyapi/</code> folders (list rule files, read a named file, find rules for a given key) before proposing changes. Your AI assistant calls these helpers automatically when needed.</p></li><li><p>The assistant writes the proposed rules into a <code>.easyapi/*.rules</code> file in your project (or <code>~/.easyapi/</code> for global rules). The IDE reloads on save.</p></li></ol><p>Because the skill and the in-IDE assistant share the same knowledge base, a rule authored by one is immediately understood and editable by the other.</p>',27)])])}const g=t(o,[["render",r]]);export{p as __pageData,g as default};
